import { handleQrRegistrationCodeWebRequest } from './qr-code.web-handler';

const tenant = {
  currency: 'EUR' as const,
  defaultLocation: undefined,
  discountProviders: {
    esnCard: {
      config: {},
      status: 'disabled' as const,
    },
  },
