    allowOther: false,
    receiptCountries: ['NL'],
  },
  stripeAccountId: null,
  theme: 'evorto' as const,
  timezone: 'Europe/Amsterdam',
};

const createUser = ({
  id = 'user-1',
  permissions = [],
}: {
  id?: string;
  permissions?: readonly Permission[];
} = {}) => ({
  attributes: [],
  auth0Id: `auth0|${id}`,
  communicationEmail: undefined,
  email: `${id}@example.com`,
  firstName: 'Test',
  iban: undefined,
  id,
  lastName: 'User',
  paypalEmail: undefined,
  permissions,
  roleIds: [],
});

const createRequestContext = ({
  authenticated = true,
  permissions = [],
  userId = 'user-1',
}: {
  authenticated?: boolean;
  permissions?: readonly Permission[];
  userId?: string;
} = {}): RequestContext =>
  ({
