  eventId: 'event-1',
  id: 'registration-1',
  status: 'CONFIRMED',
  tenantId: 'tenant-1',
  userId: 'user-1',
};

const runQrRequest = ({
  database,
  registrationId = 'registration-1',
  requestContext = createRequestContext(),
}: {
  database: unknown;
  registrationId?: string;
