    name: string;
  }[];
  templateCategories: {
    id: string;
    tenantId: string;
    title: string;
  }[];
  templates: {
    addOns: {
      id: string;
      isPaid: boolean;
      registrationOptionIds: string[];
      title: string;
    }[];
