import { describe, expect, it } from 'vitest';
import * as HttpServerResponse from 'effect/unstable/http/HttpServerResponse';

import { applySecurityHeaders } from './security-headers';

describe('applySecurityHeaders', () => {
  it('allows the first-party scanner camera and denies unused sensors', () => {
    const response = applySecurityHeaders(HttpServerResponse.text('ok'));

    expect(response.headers['permissions-policy']).toBe(
      'camera=(self), geolocation=(), microphone=()',
    );
  });
});

import type { Page } from '@playwright/test';

export type MockCameraMode = 'allowed' | 'denied';

export const installMockCamera = async (
  page: Page,
  mode: MockCameraMode,
): Promise<void> => {
  await page.addInitScript((cameraMode: MockCameraMode) => {
    const getUserMedia = async (): Promise<MediaStream> => {
      if (cameraMode === 'denied') {
        throw new DOMException('Camera permission denied', 'NotAllowedError');
      }

      const canvas = document.createElement('canvas');
      canvas.hidden = true;
      canvas.height = 240;
      canvas.width = 320;
      document.documentElement.append(canvas);
      return canvas.captureStream(5);
    };

    Object.defineProperty(navigator, 'mediaDevices', {
      configurable: true,
      value: {
        enumerateDevices: async () => [
          {
            deviceId: 'mock-camera',
            groupId: 'mock-camera-group',
            kind: 'videoinput',
            label: 'Mock camera',
            toJSON: () => ({}),
          },
        ],
        getSupportedConstraints: () => ({ facingMode: true, width: true }),
        getUserMedia,
      },
    });
  }, mode);
};

