import { getId } from '../../../helpers/get-id';
import {
  adminStateFile,
  usersToAuthenticate,
} from '../../../helpers/user-data';
import {
  eventRegistrationOptions,
  eventRegistrations,
} from '../../../src/db/schema';
import { expect, test } from '../../support/fixtures/parallel-test';
import { takeScreenshot } from '../../support/reporters/documentation-reporter';
import { installMockCamera } from '../../support/utils/mock-camera';

test.use({ storageState: adminStateFile });

test('Check in event attendees', async ({
  database,
  page,
  seeded,
}, testInfo) => {
  const eventId = seeded.scenario.events.past.eventId;
  const event = seeded.events.find((seededEvent) => seededEvent.id === eventId);
  if (!event) {
    throw new Error('Expected seeded past event for check-in documentation');
  }

  const participantOption = event.registrationOptions.find(
    (option) => !option.organizingRegistration,
  );
  if (!participantOption) {
    throw new Error(
      'Expected seeded participant option for check-in documentation',
    );
  }

  const attendee = usersToAuthenticate.find((user) => user.roles === 'user');
  if (!attendee) {
    throw new Error('Expected regular user fixture for check-in documentation');
  }

  const [optionBefore] = await database
    .select({ checkedInSpots: eventRegistrationOptions.checkedInSpots })
    .from(eventRegistrationOptions)
    .where(
      and(
        eq(eventRegistrationOptions.eventId, eventId),
        eq(eventRegistrationOptions.id, participantOption.id),
      ),
    );
  if (!optionBefore) {
    throw new Error(
      `Expected registration option "${participantOption.id}" for check-in documentation`,
    );
  }

  const registrationId = getId();

  try {
    await database.insert(eventRegistrations).values({
      checkedInGuestCount: 0,
      eventId,
      guestCount: 2,
      id: registrationId,
      registrationOptionId: participantOption.id,
      status: 'CONFIRMED',
      tenantId: seeded.tenant.id,
      userId: attendee.id,
    });

    await installMockCamera(page, 'allowed');
    const appResponse = await page.goto('/');

    expect(appResponse?.headers()['permissions-policy']).toBe(
      'camera=(self), geolocation=(), microphone=()',
    );
    await testInfo.attach('markdown', {
      body: `
{% callout type="note" title="Before you start" %}
You need a confirmed organizer/helper registration for the event or the **Organize all events** permission. Check-in is available during the event's check-in window. Use a secure, current browser on a device with a camera.
{% /callout %}

# Check in event attendees

This guide explains the complete check-in flow, including camera access, attendee verification, guests arriving at different times, and duplicate scans.

## Open the scanner

1. Sign in to the tenant that owns the event.
2. Select **Scanner** in the main navigation.
3. If the browser asks for camera access, choose **Allow**.
4. Ask the attendee to open the confirmed ticket from their event registration page and hold its QR code inside the camera frame.

The ticket identifies a registration; it is not permission to check someone in by itself. Evorto still verifies your organizer access, the tenant, the event, and the registration status.
`,
    });

    const scanLink = page.getByRole('link', { exact: true, name: 'Scanner' });
    await expect(scanLink).toBeVisible();
    await takeScreenshot(
      testInfo,
      scanLink,
      page,
      'Open Scanner from navigation',
    );
    await scanLink.click();

    await expect(
      page.getByRole('heading', { level: 1, name: 'Scanner' }),
    ).toBeVisible();
    await expect(
      page.getByRole('status').filter({ hasText: 'Camera ready.' }),
    ).toBeVisible();
    await takeScreenshot(
      testInfo,
      page.locator('app-scanner'),
      page,
      'Camera ready to scan a ticket',
    );

    await testInfo.attach('markdown', {
      body: `
### If the camera does not start

- Allow camera access for this site in the browser settings, then select **Try camera again**.
- Close another app that may be using the camera.
- If the device has no usable camera, scan the ticket with a phone's camera and open its Evorto link while signed in as an authorized organizer.
- A visible error is different from an invalid ticket. Do not check someone in until Evorto shows the registration details.

## Verify the registration

After a valid ticket is scanned, check the attendee name, event, registration option, registration status, and any ESNcard notice before confirming. Evorto warns when the ticket belongs to the signed-in organizer, the event is too far in the future, the registration is not confirmed, or it has already been checked in.
`,
    });

    await page.goto(`/scan/registration/${registrationId}`);
    await expect(
      page.getByRole('heading', { level: 1, name: 'Registration scanned' }),
    ).toBeVisible();
    await expect(page.getByText('Includes 2 guests.')).toBeVisible();
    await expect(page.getByText('0 checked in, 2 remaining.')).toBeVisible();
    await page.getByLabel('Guests to check in now').fill('1');
    await expect(
      page.getByRole('button', { name: 'Confirm 2 check-ins' }),
    ).toBeVisible();
    await takeScreenshot(
      testInfo,
      page.locator('app-handle-registration'),
      page,
      'Verify attendee and first arriving guest',
    );
    await page.getByRole('button', { name: 'Confirm 2 check-ins' }).click();
    await expect(page.getByText('Check-in recorded')).toBeVisible();

    await expect
      .poll(async () => {
        const registration = await database.query.eventRegistrations.findFirst({
          columns: {
            checkedInGuestCount: true,
            checkInTime: true,
          },
          where: { id: registrationId },
        });
        const option = await database.query.eventRegistrationOptions.findFirst({
          columns: { checkedInSpots: true },
          where: { id: participantOption.id },
        });

        return {
          attendeeCheckedIn: registration?.checkInTime !== null,
          checkedInGuestCount: registration?.checkedInGuestCount,
          checkedInSpots: option?.checkedInSpots,
        };
      })
      .toEqual({
        attendeeCheckedIn: true,
        checkedInGuestCount: 1,
        checkedInSpots: optionBefore.checkedInSpots + 2,
      });

    await testInfo.attach('markdown', {
      body: `
## Check in guests who arrive later

The first confirmation above checks in the attendee and one guest. If another guest arrives later, scan the same ticket again. Evorto shows how many guests are already checked in and how many remain. Select only the number arriving now.
`,
    });

    await page.goto(`/scan/registration/${registrationId}`);
    await expect(page.getByText('1 checked in, 1 remaining.')).toBeVisible();
    await page.getByLabel('Guests to check in now').fill('1');
    await page.getByRole('button', { name: 'Confirm check-in' }).click();
    await expect(page.getByText('Check-in recorded')).toBeVisible();

    await page.goto(`/scan/registration/${registrationId}`);
    await expect(page.getByText('Already checked in')).toBeVisible();
    await expect(page.getByText('2 checked in, 0 remaining.')).toBeVisible();
    await takeScreenshot(
      testInfo,
      page.locator('app-handle-registration'),
      page,
      'Completed check-in and duplicate-scan warning',
    );

    await page.goto(`/events/${eventId}/organize`);
    await expect(page.getByTestId('event-organize-checked-in-stat')).toHaveText(
      new RegExp(`^${optionBefore.checkedInSpots + 3}\\s*Checked In$`),
    );
    await takeScreenshot(
      testInfo,
      page.getByTestId('event-organize-checked-in-stat'),
      page,
      'Organizer checked-in total',
    );

    await testInfo.attach('markdown', {
      body: `
## What completion means

The organizer overview increases by the attendee plus the guests actually checked in. Re-scanning a fully checked-in ticket does not add to the count again; Evorto shows **Already checked in** instead.

Never bypass a warning by changing the URL or using another tenant. Ask a tenant administrator to review your organizer access or the attendee's registration when the displayed details are not correct.
`,
    });
  } finally {
    await database
      .delete(eventRegistrations)
      .where(eq(eventRegistrations.id, registrationId));
    await database
      .update(eventRegistrationOptions)
      .set({ checkedInSpots: optionBefore.checkedInSpots })
      .where(eq(eventRegistrationOptions.id, participantOption.id));
  }
});
| ADMIN-001  | P1       | Platform admin     | Platform admins have broad permissions but cannot perform normal tenant actions without tenant membership. |
| CI-001     | P1       | CI/docs            | CI silently excludes all `@finance` generated docs despite those flows being product-facing.               |
| TEST-001   | P1       | Manual approval    | The newly supported application/manual-approval journey has no page-backed spec or generated doc.          |
| TEST-002   | P1       | Roles              | Existing-user role assignment has no mutation/readback browser or docs coverage.                           |
| SEC-002    | P2       | Links              | Approval emails and Stripe return URLs trust caller-provided `Origin`.                                     |
| OPS-001    | P2       | Notifications      | A process crash can leave outbox rows permanently in `sending`.                                            |
| DATA-001   | P2       | Tenancy            | Cross-tenant role/registration tuple integrity is enforced in handlers but not by database constraints.    |
| UX-001     | P2       | Permissions        | Template actions are visible even when the user lacks the corresponding capability.                        |
| UX-002     | P2       | Resilience         | Several core views have no first-load error/retry state.                                                   |
| UX-003     | P2       | Location           | Location-provider/configuration failures are presented as “no results.”                                    |
| UI-001     | P2       | Theming            | The Material/Tailwind semantic success/warning token bridge is incomplete.                                 |
| A11Y-001   | P2       | Accessibility      | Reusable icon selection and several icon-only actions lack keyboard or accessible-name support.            |
| TEST-003   | P1       | Release confidence | CI has E2E and an implicit Docker build, but no branch protection, lint, unit, or Knope quality gate.      |
| TEST-004   | P2       | Coverage           | New tenant operational settings and the global Email Outbox lack durable UI/docs coverage.                 |
| EFFECT-001 | P3       | Contracts          | The tenant settings RPC accepts `defaultLocation` through `Schema.Any`.                                    |
| EFFECT-002 | P3       | Tests              | One server Effect test bypasses the project’s preferred `it.effect` runtime.                               |

## Release blockers and high-risk findings

### SCAN-001 — Global security policy makes QR check-in unusable

**Severity:** P0
**Why it matters:** QR scanning is a core organizer workflow.

**Evidence**

- `src/server/http/security-headers.ts:4` sends `Permissions-Policy: camera=(), geolocation=(), microphone=()`.
- `src/server.ts:381-398` applies that header through global middleware, with no scanner-route exception.
- `src/app/scanning/scanner/scanner.component.ts:106-139` creates `QrScanner` and calls `scanner.start()`.

`camera=()` denies camera access to the document itself, so browser permission cannot make the scanner work. The component’s retry guidance therefore sends an organizer toward a browser setting that cannot fix the policy-level denial.

**Fix direction**

1. Permit the authenticated first-party scanner with `camera=(self)` if the application is never embedded, or apply the narrower policy only to the scanner response.
2. Preserve restrictive policies for microphone/geolocation unless a real product path needs them.
3. Add a server/header regression test and a page-backed camera-permission failure/success check.

### PAY-001 — Concurrent manual approval can create duplicate payments

**Severity:** P0
**Why it matters:** Two organizers can approve the same pending application concurrently, leading to duplicate capacity reservations, two Checkout sessions, and potentially two charges.

**Evidence**

- `src/server/effect/rpc/handlers/events/event-registration.service.ts:465-476` checks for a pending transaction before entering the approval transaction.
- `src/server/effect/rpc/handlers/events/event-registration.service.ts:571-670` reserves capacity but leaves a paid application registration in `PENDING`; the conditional status update therefore does not claim the approval.
- `src/server/effect/rpc/handlers/events/event-registration.service.ts:729-867` creates the Checkout session and pending transaction later, outside that reservation transaction.
- `src/server/http/stripe-webhook.web-handler.ts:481-513` marks a transaction successful before it discovers whether the registration was already confirmed by another event.

**Fix direction**

1. Atomically claim approval with a distinct state or a durable lease before any Stripe call.
2. Create/record exactly one live registration-payment transaction under the same lock, then reuse its Checkout session/idempotency key.
3. Add a database constraint for one live pending registration payment and a concurrency test with two simultaneous approvals.

### PAY-002 — Checkout webhook handling does not prove local payment ownership

**Severity:** P1
**Why it matters:** Stripe is the payment source of truth, but the completion and expiry handlers can mutate a registration based on webhook metadata that is not tied back to the expected local Checkout session.

**Evidence**

- `src/server/http/stripe-webhook.web-handler.ts:80-120` accepts complete metadata even when no local transaction is found for the session/payment intent.
- `src/server/http/stripe-webhook.web-handler.ts:481-536` conditionally updates a transaction only by id/status/tenant, ignores whether it changed a row, then confirms the registration.
- The completion/expiry paths do not require the expected `stripeCheckoutSessionId`, expected payment intent, registration id, amount/currency, or connected account event to match before changing registration/capacity state.

