import * as BunRuntime from '@effect/platform-bun/BunRuntime';
import { Effect } from 'effect';
import path from 'node:path';

// Generates worktree-local runtime ports and names so parallel Docker/test
// runs do not collide with the main checkout or other Codex worktrees.
const DEFAULT_APP_HOST_PORT = 4200;
const DEFAULT_NEON_LOCAL_HOST_PORT = 55_432;
const DEFAULT_MINIO_CONSOLE_HOST_PORT = 9001;
const DEFAULT_MINIO_HOST_PORT = 9000;
const OUTPUT_FILE_PATH = path.resolve(process.cwd(), '.env.dev');

const databaseName = process.env['NEON_DATABASE_NAME']?.trim() || 'appdb';

const deriveSeed = (): string => {
  const runId = process.env['GITHUB_RUN_ID']?.trim();
  const runAttempt = process.env['GITHUB_RUN_ATTEMPT']?.trim();
  if (runId) {
    return `${runId}:${runAttempt || '1'}`;
  }

  return process.cwd();
};

const seed = deriveSeed();
const digest = new Bun.CryptoHasher('sha256').update(seed).digest('hex');

const parsePort = (value: string | undefined): number | undefined => {
  const parsed = Number.parseInt(value ?? '', 10);
  if (!Number.isInteger(parsed) || parsed < 1024 || parsed > 65_535) {
    return undefined;
  }
  return parsed;
};

const readHexChunk = (start: number): number =>
  Number.parseInt(digest.slice(start, start + 8), 16);

const derivePort = (base: number, span: number, chunkStart: number): number =>
  base + (readHexChunk(chunkStart) % span);

const resolvePort = (names: readonly string[], fallback: number): number => {
  for (const name of names) {
    const parsed = parsePort(process.env[name]);
    if (parsed !== undefined) {
      return parsed;
    }
  }

  return fallback;
};

const appHostPort = resolvePort(
  ['APP_HOST_PORT'],
  derivePort(DEFAULT_APP_HOST_PORT, 400, 0),
);
const neonLocalHostPort = resolvePort(
  ['NEON_LOCAL_HOST_PORT'],
  derivePort(DEFAULT_NEON_LOCAL_HOST_PORT, 400, 8),
);
const minioHostPort = resolvePort(
  ['MINIO_HOST_PORT'],
  derivePort(DEFAULT_MINIO_HOST_PORT, 400, 16),
);
const minioConsoleHostPort = resolvePort(
  ['MINIO_CONSOLE_HOST_PORT'],
  derivePort(DEFAULT_MINIO_CONSOLE_HOST_PORT, 400, 24),
);

const sanitizeProjectName = (value: string): string =>
  value
    .toLowerCase()
    .replaceAll(/[^a-z0-9_-]+/g, '-')
    .replaceAll(/-+/g, '-')
    .replaceAll(/^-|-$/g, '')
    .slice(0, 40);

const defaultProjectName = (): string => {
  const basename = path.basename(process.cwd());
  const safeBasename = sanitizeProjectName(basename || 'evorto');
  const suffix = digest.slice(0, 8);
  return `${safeBasename}-${suffix}`;
};

const composeProjectName =
  process.env['COMPOSE_PROJECT_NAME']?.trim() || defaultProjectName();
const baseUrl = `http://localhost:${appHostPort}`;
const databaseUrl = `postgresql://neon:npg@localhost:${neonLocalHostPort}/${databaseName}?sslmode=require`;

const runtimeEnvironment = {
  APP_HOST_PORT: String(appHostPort),
  BASE_URL: baseUrl,
  COMPOSE_PROJECT_NAME: composeProjectName,
  DATABASE_URL: databaseUrl,
  DELETE_BRANCH: 'true',
  MINIO_CONSOLE_HOST_PORT: String(minioConsoleHostPort),
  MINIO_HOST_PORT: String(minioHostPort),
  NEON_DATABASE_NAME: databaseName,
  NEON_LOCAL_BRANCH_TTL_HOURS: '24',
  NEON_LOCAL_HOST_PORT: String(neonLocalHostPort),
  NEON_LOCAL_PROXY: 'true',
} as const;

const escapeEnvironmentValue = (value: string): string => JSON.stringify(value);

const outputLines = [
  '# THIS FILE IS AUTO-GENERATED. DO NOT EDIT MANUALLY.',
  '# Worktree-specific overrides for local runtime commands.',
  ...Object.entries(runtimeEnvironment).map(
    ([key, value]) => `${key}=${escapeEnvironmentValue(value)}`,
  ),
  '',
];

const main = Effect.gen(function* () {
  yield* Effect.tryPromise({
    catch: (cause) =>
      new Error(`Failed to write runtime env file at ${OUTPUT_FILE_PATH}`, {
        cause: cause instanceof Error ? cause : new Error(String(cause)),
      }),
    try: () => Bun.write(OUTPUT_FILE_PATH, outputLines.join('\n')),
  });
  yield* Effect.logInfo(`Wrote ${OUTPUT_FILE_PATH}`);
});

BunRuntime.runMain(main);

```bash
bun run test:e2e:install
```

CI runs `bunx playwright install --with-deps`, but local macOS/Linux development only needs the package script unless the host is missing OS-level browser dependencies.

Local runs use Playwright's bundled Chromium by default. For exploratory runs
on a machine that already has Google Chrome installed, set
`E2E_BROWSER_CHANNEL=chrome` to use the system Chrome channel without
installing the bundled browser cache.

## Runtime Environment Precedence

Application runtime config resolves in this precedence order:

- real environment variables
- `.env.dev.local`
- `.env.dev`
- `.env`
- in-code defaults

External-tool package scripts use `dotenv -c dev`. Because `dotenv-cli` is first-wins, the effective dotenv precedence for those scripts is:

- `.env.dev.local`
- `.env.local` if someone creates it manually; this file is unsupported and should not exist
- `.env.dev`
- `.env`

CI should not rely on dotenv files at all; workflows provide values via exported environment variables.

## Deterministic E2E Environment

Playwright defaults deterministic test values in code via
`src/shared/testing/deterministic-test-defaults.ts`, so local runs do not need
extra flags.

Default values:

- `E2E_NOW_ISO=2026-09-15T12:00:00.000Z`
- `E2E_SEED_KEY=evorto-e2e-default-v1`

Optional overrides:

- `E2E_NOW_ISO`
- `E2E_SEED_KEY`

Keep `E2E_NOW_ISO` ahead of the real current date or deterministic checkout expiry behavior will break.

## Baseline vs Integration Projects

Playwright separates external-service coverage with dedicated projects:

- baseline:
  - `local-chrome-baseline`
  - `docs-baseline`
- integration-only:
  - `local-chrome-integration`
  - `docs-integration`

CI infers whether integration-only credentials are required from the selected Playwright projects.
If you select `local-chrome-integration` or `docs-integration`, CI/runtime validation demands the extra external-service credentials.
UI mode is intentionally unrestricted and does not force integration-only credentials at startup.
CI baseline jobs set `E2E_SELECTED_PROJECTS` so Playwright worker processes
that no longer expose the original CLI `--project` flags still use the
baseline credential contract.

