import { DatePipe } from '@angular/common';
import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  signal,
} from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { RouterLink } from '@angular/router';
import { FaDuotoneIconComponent } from '@fortawesome/angular-fontawesome';
import { faArrowLeft } from '@fortawesome/duotone-regular-svg-icons';
import {
  injectMutation,
  injectQuery,
  QueryClient,
} from '@tanstack/angular-query-experimental';
import { DateTime } from 'luxon';

import { AppRpc } from '../../core/effect-rpc-angular-client';
import { getErrorMessage } from '../../core/error-message';

export const scanCheckInButtonLabel = ({
  completed,
  pending,
  spotCount,
}: {
  completed: boolean;
  pending: boolean;
  spotCount: number;
}): string => {
  if (pending) {
    return 'Checking in...';
  }

  if (completed) {
    return 'Checked in';
  }

  return spotCount > 1 ? `Confirm ${spotCount} check-ins` : 'Confirm check-in';
};

export const scanSpotCountLabel = (spotCount: number): string =>
  spotCount === 1 ? '1 spot now' : `${spotCount} spots now`;

export const scanCheckInActionDisabled = ({
  allowCheckin,
  completed,
  mutationPending,
  spotCount,
}: {
  allowCheckin: boolean;
  completed: boolean;
  mutationPending: boolean;
  spotCount: number;
}): boolean => !allowCheckin || completed || mutationPending || spotCount < 1;

export const scanGuestCheckInCountFromInput = ({
  inputValue,
  remainingGuestCount,
}: {
  inputValue: string;
  remainingGuestCount: number;
}): number => {
  const nextGuestCount = Number.parseInt(inputValue, 10);
  return Math.max(
    0,
    Math.min(
      Number.isNaN(nextGuestCount) ? 0 : nextGuestCount,
      remainingGuestCount,
    ),
  );
};

@Component({
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    FaDuotoneIconComponent,
    MatButtonModule,
    MatFormFieldModule,
    MatInputModule,
    RouterLink,
    DatePipe,
  ],
  selector: 'app-handle-registration',
  styles: ``,
  templateUrl: './handle-registration.component.html',
})
export class HandleRegistrationComponent {
  public readonly registrationId = input.required<string>();
  private readonly rpc = AppRpc.injectClient();
  protected readonly checkInMutation = injectMutation(() =>
    this.rpc.events.checkInRegistration.mutationOptions(),
  );
  protected readonly scanResultQuery = injectQuery(() =>
    this.rpc.events.registrationScanned.queryOptions({
      registrationId: this.registrationId(),
    }),
  );
  protected readonly guestCheckInCount = signal(0);
  protected readonly selectedGuestCheckInCount = computed(() => {
    const scanResult = this.scanResultQuery.data();
    if (!scanResult) {
      return 0;
    }
    return Math.min(this.guestCheckInCount(), scanResult.remainingGuestCount);
  });
  protected readonly selectedSpotCheckInCount = computed(() => {
    const scanResult = this.scanResultQuery.data();
    if (!scanResult) {
      return 0;
    }
    return (
      (scanResult.attendeeCheckedIn ? 0 : 1) + this.selectedGuestCheckInCount()
    );
  });
  private readonly localCheckInCompleted = signal(false);
  protected readonly checkInCompleted = computed(
    () =>
      this.localCheckInCompleted() ||
      (this.checkInMutation.isSuccess() &&
        this.selectedSpotCheckInCount() === 0),
  );
  protected readonly faArrowLeft = faArrowLeft;
  protected readonly scanCheckInActionDisabled = scanCheckInActionDisabled;
  protected readonly scanCheckInButtonLabel = scanCheckInButtonLabel;
  protected readonly scanSpotCountLabel = scanSpotCountLabel;
  protected readonly startsSoon = computed(() => {
    const scanResult = this.scanResultQuery.data();
    if (!scanResult) return false;
    return DateTime.fromISO(scanResult.event.start).diffNow('hours').hours < 1;
  });
  private readonly queryClient = inject(QueryClient);

  checkIn() {
    const scanResult = this.scanResultQuery.data();
    if (
      scanCheckInActionDisabled({
        allowCheckin: scanResult?.allowCheckin ?? false,
        completed: this.checkInCompleted(),
        mutationPending: this.checkInMutation.isPending(),
        spotCount: this.selectedSpotCheckInCount(),
      })
    )
      return;

    this.checkInMutation.mutate(
      {
        guestCheckInCount: this.selectedGuestCheckInCount(),
        registrationId: this.registrationId(),
      },
      {
        onSuccess: async () => {
          this.localCheckInCompleted.set(true);
          await this.queryClient.invalidateQueries(
            this.rpc.queryFilter(['events', 'registrationScanned']),
          );
        },
      },
    );
  }

  updateGuestCheckInCount(event: Event) {
    const input = event.target;
    if (!(input instanceof HTMLInputElement)) {
      return;
    }
    const remainingGuestCount =
      this.scanResultQuery.data()?.remainingGuestCount ?? 0;
    this.guestCheckInCount.set(
      scanGuestCheckInCountFromInput({
        inputValue: input.value,
        remainingGuestCount,
      }),
    );
  }

  protected errorMessage(error: unknown): string {
    return getErrorMessage(error, 'Unknown error');
  }
}
<div class="mb-4 flex flex-row items-center gap-2">
  <a routerLink="/scan" mat-icon-button>
    <fa-duotone-icon [icon]="faArrowLeft" />
  </a>
  <h1 class="title-large">Registration scanned</h1>
  <div class="grow"></div>
</div>
@if (scanResultQuery.isPending()) {
  <div
    class="bg-surface text-on-surface flex animate-pulse cursor-progress flex-col gap-2 rounded-2xl p-4"
  >
    <h2 class="title-medium">Loading ...</h2>
  </div>
} @else if (scanResultQuery.isError()) {
  <div class="bg-error text-on-error rounded-2xl p-4">
    <h2 class="title-medium mb-4">There was an error</h2>
    <p class="body-medium">
      Error: {{ errorMessage(scanResultQuery.error()) }}
    </p>
  </div>
} @else if (scanResultQuery.isSuccess()) {
  <div class="bg-surface text-on-surface flex flex-col gap-2 rounded-2xl">
    <div class="border-b p-4">
      <h2 class="title-medium">Scan result</h2>
    </div>
    <div class="border-b p-2">
      <p class="title-small px-2">User</p>
      <p class="px-2">
        {{ scanResultQuery.data().user.firstName }}
        {{ scanResultQuery.data().user.lastName }}
      </p>
      @if (scanResultQuery.data().sameUserIssue) {
        <div class="bg-error text-on-error mt-2 rounded p-2">
          <p class="title-small">Registration for logged in user</p>
          <p>
            You can not scan a registration for yourself. Please ask another
            member to scan your registration.
          </p>
        </div>
      }
    </div>
    <div class="border-b p-2">
      <p class="title-small px-2">Event</p>
      <p class="px-2">{{ scanResultQuery.data().event.title }}</p>
      @if (!startsSoon()) {
        <div class="bg-error text-on-error mt-2 rounded p-2">
          <p class="title-small">Event starting in the future</p>
          <p>
            The event starts more than one hour from now, at
            {{ scanResultQuery.data().event.start | date: "medium" }}.
          </p>
        </div>
      }
    </div>
    <div class="p-2">
      <p class="title-small px-2">Registration</p>
      <p class="px-2">
        {{ scanResultQuery.data().registrationOption.title }}
      </p>
      @if (scanResultQuery.data().guestCount > 0) {
        <div class="mt-2 px-2">
          <p class="body-medium">
            Includes {{ scanResultQuery.data().guestCount }}
            {{ scanResultQuery.data().guestCount === 1 ? "guest" : "guests" }}.
          </p>
          <p class="body-small text-on-surface-variant">
            {{ scanResultQuery.data().checkedInGuestCount }} checked in,
            {{ scanResultQuery.data().remainingGuestCount }} remaining.
          </p>
        </div>
      }
      @if (scanResultQuery.data().appliedDiscountType === "esnCard") {
        <div
          class="bg-primary-container text-on-primary-container mt-2 rounded p-2"
        >
          <p class="title-small">ESNcard discount applied</p>
          <p>Verify the attendee's physical ESNcard if needed.</p>
        </div>
      }
      @if (scanResultQuery.data().registrationStatusIssue) {
        <div class="bg-error text-on-error mt-2 rounded p-2">
          <p class="title-small">Registration is not confirmed</p>
          <p>
            This registration is not confirmed, please ask the user to check if
            they paid. The registration can only be scanned if it is confirmed.
          </p>
        </div>
      }
      @if (scanResultQuery.data().alreadyCheckedInIssue) {
        <div
          class="bg-tertiary-container text-on-tertiary-container mt-2 rounded p-2"
        >
          <p class="title-small">Already checked in</p>
          <p>This registration has already been checked in.</p>
        </div>
      }
    </div>
  </div>
  @if (
    scanResultQuery.data().allowCheckin &&
    scanResultQuery.data().remainingGuestCount > 0
  ) {
    <mat-form-field appearance="outline" class="mt-4 w-full">
      <mat-label>Guests to check in now</mat-label>
      <input
        matInput
        type="number"
        min="0"
        [max]="scanResultQuery.data().remainingGuestCount"
        [value]="selectedGuestCheckInCount()"
        (input)="updateGuestCheckInCount($event)"
      />
      <span matTextSuffix>
        {{ scanSpotCountLabel(selectedSpotCheckInCount()) }}
      </span>
    </mat-form-field>
  }
  @if (checkInMutation.isError()) {
    <div class="bg-error text-on-error mt-4 rounded p-4">
      <p class="title-small">Check-in failed</p>
      <p>{{ errorMessage(checkInMutation.error()) }}</p>
    </div>
  } @else if (checkInMutation.isSuccess()) {
    <div
      class="bg-primary-container text-on-primary-container mt-4 rounded p-4"
    >
      <p class="title-small">Check-in recorded</p>
    </div>
  }
  <button
    [disabled]="
      scanCheckInActionDisabled({
        allowCheckin: scanResultQuery.data().allowCheckin,
        completed: checkInCompleted(),
        mutationPending: checkInMutation.isPending(),
        spotCount: selectedSpotCheckInCount(),
      })
    "
    class="mt-4 w-full"
    mat-raised-button
    type="button"
    (click)="checkIn()"
  >
    {{
      scanCheckInButtonLabel({
        completed: checkInCompleted(),
        pending: checkInMutation.isPending(),
        spotCount: selectedSpotCheckInCount(),
      })
